import React from "react";
import '/Home.css';
import logo1 from "../../assets/capivara 1.png";

function Home() {
    return (
        <div className="home">
            <div className="logo">
                <img src={logo1} alt="capivara" />
                <h1>GoCapiba</h1>
                <span>Colete moedas capibas e ajude a transformar Recife.</span>
            </div>
            <div className="logins">
                <button>Entrar com gov.br</button>
                <button>Entrar com Conecta Login</button>
                <button>Ou entrar como convidado</button>
            </div>
        </div>
    )
}

export default Home;
